#include <stdio.h>

int removeDuplicates(int *nums, int n) {
    if (n == 0) return 0;
    int k = 0; // index of last unique element
    for (int i = 1; i < n; ++i) {
        if (nums[i] != nums[k]) {
            ++k;
            nums[k] = nums[i];
        }
    }
    return k + 1; // number of unique elements
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int nums[30000]; // maximum possible N
        for (int i = 0; i < N; ++i) scanf("%d", &nums[i]);
        int K = removeDuplicates(nums, N);
        printf("%d\n", K);
        for (int i = 0; i < K; ++i) {
            printf("%d", nums[i]);
            if (i + 1 < K) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

