#include <bits/stdc++.h>
using namespace std;

int removeDuplicates(vector<int>& a) {
    if (a.empty()) return 0;
    int k = 0;
    for (size_t i = 1; i < a.size(); ++i) {
        if (a[i] != a[k]) {
            ++k;
            a[k] = a[i];
        }
    }
    return k + 1;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<int> nums(N);
        for (int i = 0; i < N; ++i) cin >> nums[i];
        int K = removeDuplicates(nums);
        cout << K << '\n';
        for (int i = 0; i < K; ++i) {
            if (i) cout << ' ';
            cout << nums[i];
        }
        cout << '\n';
    }
    return 0;
}

